function processData(data: string | number) {
  // data could be anything here
  if (typeof data === "string") {
    // Inside this block, TS perfectly guarantees it is a string!
    return data.toUpperCase(); 
  }
  // Down here, TS mathematically knows it MUST be a number now!
  return data.toFixed(2);
}

interface Fish { swim: () => void; }
interface Bird { fly: () => void; }

// This special return type 'pet is Fish' is the magic key!
function isFish(pet: Fish | Bird): pet is Fish {
  return (pet as Fish).swim !== undefined;
}

let pet: Fish | Bird = getPet();
if (isFish(pet)) {
  pet.swim(); // TS exactly knows it's a Fish here!
}
